sql:
SELECT residue_name
FROM residues
WHERE struct_id = 1;

SELECT DISTINCT residue1_id, residue2_id
FROM residue_interactions
WHERE interaction_type = 'salt bridge';

SELECT similarity_score, alignment_method, alignment_score, alignment_length
FROM structural_similarities
WHERE struct1_id = 0 AND struct2_id = 1;

SELECT users.username, protein_structures.structure_name
FROM users, protein_structures
WHERE users.role = 'researcher';

external_knowledge:
- Clarity beyond the misty veil of 2 angstroms refers to the resolution being greater than 2.0;
- Dance under the moonlight with the delicate touch of hydrogen bonds means the interactions are specifically hydrogen bonds;
- Resonant whispers refer to the interaction strength of these interactions.

sql:
SELECT author
FROM protein_structures
WHERE structure_name = 'SARS-CoV-2 main protease';

SELECT struct_id, COUNT(chain_id) AS number_of_chains 
FROM chains 
GROUP BY struct_id;

SELECT structure_name, pdb_id
FROM protein_structures
ORDER BY struct_id DESC;

SELECT structure_name, ligands
FROM protein_structures
WHERE structure_name LIKE 'Helicase%';

SELECT structure_name, protein_family
FROM protein_structures
WHERE resolution > 2.0 AND struct_id = 1;

SELECT AVG(coordinate_x) AS average_x_coordinate
FROM residues
WHERE struct_id = 1;

SELECT DISTINCT structure_name, species
FROM protein_structures
WHERE resolution > 3.0 AND species = 'Homo Sapiens';
